      "type": "activity",
      "title": "Construct the Square Root Spiral",
      "unit_name": "Number System",
      "chapter_name": "Number System",
      "details": "Construct the square root spiral to represent rational and irrational numbers through visual models."
    },
    {
      "type": "activity",
      "title": "Tower of Hanoi Puzzle",
      "unit_name": "Algebra",
      "chapter_name": "Sequences and Progressions",
      "details": "Solve the Tower of Hanoi puzzle to model patterns in sequences using computational thinking."
    },
    {
      "type": "activity",
      "title": "Visualise Algebraic Identities with Geometric Models",
      "unit_name": "Algebra",
      "chapter_name": "Exploring Algebraic Identities",
      "details": "Determine factors of algebraic expressions using geometric models and visualising identities."
    },
    {
      "type": "activity",
      "title": "Floor Plan on a Grid",
      "unit_name": "Coordinate Geometry",
      "chapter_name": "Coordinate Geometry",
      "details": "Represent a floor plan on a grid using coordinates to specify locations and positions."
    },
    {
      "type": "activity",
      "title": "Discovering Euclid's Definitions via Sulbasutras",
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry: Axioms and Postulates",
      "details": "Describe contributions of India, Egypt, and Greece; explain the construction of a square as described in Baudhayana's Sulbasutras."
    },
    {
      "type": "activity",
      "title": "Paper Manipulation for Geometric Patterns",
      "unit_name": "Geometry",
      "chapter_name": "4-gons (Quadrilaterals)",
      "details": "Engage in drawing, measurement and paper manipulation activities to discover geometric patterns involving triangles and 4-gons."
    },
    {
      "type": "activity",
      "title": "Cultural Motifs Involving Circles",
      "unit_name": "Geometry",
      "chapter_name": "Circles",
      "details": "Identify cultural motifs involving circles, such as the Dharmachakra, Ashoka Chakra, and Sudarshan Chakra."
    },
    {
      "type": "activity",
      "title": "Squaring a Rectangle Proof Activity",
      "unit_name": "Mensuration",
      "chapter_name": "Area of shapes, Heron's formula, Squaring a rectangle, Circle area, Brahmagupta's formula",
      "details": "Explain the classical problem of 'squaring' a given shape using proof from Baudhayana's Sulbasutras."
    },
    {
      "type": "activity",
      "title": "Real-life Data Analysis and Graphical Representation",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics",
      "details": "Collect, organise, visualise data to answer a statistical investigative question; read stacked bar graphs."
    },
    {
      "type": "activity",
      "title": "Randomness Simulation Experiments",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Introduction to Probability",
      "details": "Use computational thinking strategies, such as pattern recognition and simulation, to model random experiments."
    }
  ],
  "projects": [
    {
      "title": "Historical Approximations of Pi",
      "unit_name": "Mensuration",
      "chapter_name": "Area of shapes, Heron's formula, Squaring a rectangle, Circle area, Brahmagupta's formula",
      "details": "List historical approximations to π from Archimedes, Aryabhata, and Zu Chongzhi; explain ancient civilisations' methods for circle area."
    },
    {
      "title": "Applications of Circles in Transport and Technology",
      "unit_name": "Geometry",
      "chapter_name": "Circles",
      "details": "Explain how circular wheels have influenced transport, farming, building, and technology; identify cultural motifs."
    },
    {
      "title": "Statistical Investigation Project",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics",
      "details": "Apply computational thinking strategies to analyse real-life data, create appropriate graphical representations (stacked bar graphs), and interpret mean, median, mode for decision-making."
    }
  ],
  "practicals": [
    {
      "title": "Mathematics Laboratory Activities",
      "unit_name": "Number System",
      "chapter_name": "Number System",
      "details": "Lab activities to be done from prescribed books (NCERT/CBSE) covering representation of rational numbers on number line and density proofs."
    },
    {
      "title": "Geometric Constructions Lab",
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry: Axioms and Postulates",
      "details": "Construct geometrical shapes like bisectors of line segments, angles, triangles, and other polygons satisfying given constraints using stated axioms."
    },
    {
      "title": "3-D Shapes Surface Area and Volume Lab",
      "unit_name": "Mensuration",
      "chapter_name": "Cuboids, Cylinders, Cones, Pyramids, Spheres",
      "details": "Compute surface area/volume of cuboids, cylinders, cones, pyramids, spheres (including hemispheres) using computational thinking."
    },
    {
      "title": "Prescribed Laboratory Manual Activities",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Introduction to Probability",
      "details": "Lab activities from 'Guidelines for Mathematics Laboratory in Schools' covering empirical probability experiments and theoretical probability concepts."
    }
  ]
}
